const Web3 = require('web3');
const fs = require('fs');

// Set up web3 provider (e.g., Infura, Alchemy)
const providerUrl = 'https://mainnet.infura.io/v3/YOUR_PROJECT_ID';
const web3 = new Web3(new Web3.providers.HttpProvider(providerUrl));

// Load private keys from file
const privateKeyFile = './private_keys.json';
const privateKeys = JSON.parse(fs.readFileSync(privateKeyFile, 'utf8'));

// Function to sign transaction with a specific private key
function signTransaction(privateKey, tx) {
  const wallet = new web3.eth.accounts.Wallet.fromPrivateKey(privateKey);
  return wallet.signTransaction(tx);
}

// Function to send ETH from one address to another
async function sendEth(fromAddress, toAddress, amount) {
  const privateKey = privateKeys[fromAddress];
  if (!privateKey) throw new Error(`Private key not found for ${fromAddress}`);

  const tx = {
    from: fromAddress,
    to: toAddress,
    value: web3.utils.toWei(amount.toString(), 'ether'),
    gas: '20000',
    gasPrice: web3.utils.toWei('20', 'gwei')
  };

  const signedTx = signTransaction(privateKey, tx);
  await web3.eth.sendSignedTransaction(signedTx.rawTransaction);
}

